mapper.insert:
INSERT INTO STOCECMT ( GATE_CD , BUYER_CD , CONT_NUM , CONT_CNT , PR_BUYER_CD , PR_DEPT_CD , VENDOR_CD , ITEM_SQ , REG_DATE , REG_USER_ID , MOD_DATE , MOD_USER_ID , DEL_FLAG , ITEM_CD , ITEM_DESC , ITEM_SPEC , MAKER_CD , MAKER_PART_NO , ORIGIN_CD , ITEM_QT , UNIT_CD , ITEM_PRC , ITEM_AMT , SW_BIZ_AMT , MNT_SANGJU_YN , CONSUMER_AMT , FC_MNT_TERM , CH_RATE , DOIB_AMOUNT , MNT_RATE , MNT_SDAY , MNT_EDAY , MNT_GUR_MONTH , RT_INSP_PERIOD , FALT_RC_TG_TIME , DUE_DATE , PR_NUM , PR_SQ , PURCHASE_TYPE , EXEC_NUM , EXEC_SQ , CONT_WT_NUM , PB_BUYER_CD ) SELECT #{ses.gateCd} AS GATE_CD , #{ses.companyCd} AS BUYER_CD , #{CONT_NUM} AS CONT_NUM , #{CONT_CNT} AS CONT_CNT , CNDT.PR_BUYER_CD , CNDT.PR_DEPT_CD , CNDT.VENDOR_CD , ROWNUM AS ITEM_SQ , SYSDATE AS REG_DATE , #{ses.userId} AS REG_USER_ID , SYSDATE AS MOD_DATE , #{ses.userId} AS MOD_USER_ID , '0' AS DEL_FLAG , CNDT.ITEM_CD , CNDT.ITEM_DESC , CNDT.ITEM_SPEC , CNDT.MAKER_CD , CNDT.MAKER_PART_NO , CNDT.ORIGIN_CD , CNDT.EXEC_QT AS ITEM_QT , CNDT.UNIT_CD -- 2021.06.18 품의시 TCO포함 품의인 경우 계약금액은 TCO 포함한 금액으로 진행한다. --, CNDT.UNIT_PRC AS ITEM_PRC --, CNDT.EXEC_AMT AS ITEM_AMT ,(CASE WHEN CNHD.EXEC_TCO_FLAG = '1' THEN (CNDT.EXEC_AMT, 0) + (CNDT.TCO_AMT, 0) ELSE (CNDT.EXEC_AMT, 0) END) / (CNDT.EXEC_QT, 1) AS ITEM_PRC ,(CASE WHEN CNHD.EXEC_TCO_FLAG = '1' THEN (CNDT.EXEC_AMT, 0) + (CNDT.TCO_AMT, 0) ELSE (CNDT.EXEC_AMT, 0) END) AS ITEM_AMT , CNDT.SW_BUS_PRICE AS SW_BIZ_AMT , CNDT.MNT_SANGJU_YN , CNDT.CONSUMER_AMT , CNDT.FC_MNT_TERM , CNDT.CH_RATE , CNDT.DOIB_AMT AS DOIB_AMOUNT , CNDT.MNT_RATE , CNDT.MNT_SDAY , CNDT.MNT_EDAY , CNDT.MNT_GUR_MONTH , CNDT.RT_INSP_PERIOD , CNDT.FALT_RC_TG_TIME , CNDT.DUE_DATE , CNDT.PR_NUM , CNDT.PR_SQ , CNDT.PURCHASE_TYPE , CNDT.EXEC_NUM , CNDT.EXEC_SQ , ECHB.CONT_WT_NUM , CNDT.PB_BUYER_CD FROM STOCCNDT CNDT JOIN STOCCNHD CNHD ON (CNHD.GATE_CD = CNDT.GATE_CD AND CNHD.BUYER_CD = CNDT.BUYER_CD AND CNHD.EXEC_NUM = CNDT.EXEC_NUM AND CNHD.DEL_FLAG = '0') JOIN STOCECHB ECHB ON (CNDT.GATE_CD = ECHB.GATE_CD AND CNDT.BUYER_CD = ECHB.BUYER_CD AND CNDT.EXEC_NUM = ECHB.EXEC_NUM AND CNDT.EXEC_SQ = ECHB.EXEC_SQ) WHERE CNDT.GATE_CD = #{ses.gateCd} AND CNDT.BUYER_CD = #{ses.companyCd} AND CNDT.EXEC_NUM || CNDT.EXEC_SQ IN
#{value}
AND CNDT.DEL_FLAG = '0' ORDER BY CNDT.EXEC_SQ

INSERT INTO STOCECCT ( GATE_CD , BUYER_CD , CONT_NUM , CONT_CNT , REG_DATE , REG_USER_ID , MOD_DATE , MOD_USER_ID , DEL_FLAG , PROGRESS_CD , CONT_DATE , CONT_START_DATE , CONT_END_DATE , CONT_DESC , CONT_REQ_CD , CUR , CONT_AMT , VAT_TYPE , SUPPLY_AMT , VAT_AMT , DEPT_CD , CONT_USER_ID , VENDOR_CD , VENDOR_PIC_USER_NM , VENDOR_PIC_USER_EMAIL , VENDOR_PIC_USER_CELL_NUM , CERT_TYPE , AMT_TYPE , MANUAL_CONT_FLAG , AUTO_RENEW_FLAG , SIGN_STATUS , CONT_RMK , CREATE_TYPE ) SELECT #{ses.gateCd} AS GATE_CD , #{ses.companyCd} AS BUYER_CD , #{CONT_NUM} AS CONT_NUM , #{CONT_CNT} AS CONT_CNT , SYSDATE AS REG_USER_ID , #{ses.userId} AS REG_DATE , SYSDATE AS MOD_USER_ID , #{ses.userId} AS MOD_DATE , '0' AS DEL_FLAG , '4200' AS PROGRESS_CD -- 작성중(4200) , (SYSDATE, 'YYYYMMDD') AS CONT_DATE , NULL AS CONT_START_DATE , NULL AS CONT_END_DATE , CNHD.EXEC_SUBJECT AS CONT_DESC , '10' AS CONT_REQ_CD -- 신규(10) , CNHD.CUR -- CUR : 통화 , CNDT.CONT_AMT , CNHD.VAT_TYPE ,(CASE WHEN CNHD.VAT_TYPE = '1' THEN TRUNC(TO_NUMBER(CNDT.CONT_AMT) / 1.1) WHEN CNHD.VAT_TYPE = '2' THEN TO_NUMBER(CNDT.CONT_AMT) WHEN CNHD.VAT_TYPE = '0' THEN TO_NUMBER(CNDT.CONT_AMT) END) AS SUPPLY_AMT ,(CASE WHEN CNHD.VAT_TYPE = '1' THEN TO_NUMBER(CNDT.CONT_AMT) - TRUNC(TO_NUMBER(CNDT.CONT_AMT) / 1.1) WHEN CNHD.VAT_TYPE = '2' THEN TRUNC(TO_NUMBER(CNDT.CONT_AMT) * 0.1) WHEN CNHD.VAT_TYPE = '0' THEN 0 END) AS VAT_AMT , #{ses.deptCd} AS DEPT_CD , #{ses.userId} AS CONT_USER_ID , CNDT.VENDOR_CD , NULL AS VENDOR_PIC_USER_NM , NULL AS VENDOR_PIC_USER_EMAIL , NULL AS VENDOR_PIC_USER_CELL_NUM , NULL AS CERT_TYPE -- 인증서종류 , CNDT.CONT_TYPE3 AS AMT_TYPE -- 금액구분 , '1' AS MANUAL_CONT_FLAG -- 수기계약여부 , '0' AS AUTO_RENEW_FLAG -- 자동갱신여부 , 'T' AS SIGN_STATUS -- 작성중(T) , NULL AS CONT_RMK , 'CN' AS CREATE_TYPE -- 계약서작성구분(선정품의) FROM STOCCNHD CNHD JOIN (SELECT DT.GATE_CD, DT.BUYER_CD, DT.EXEC_NUM, DT.VENDOR_CD, DT.CONT_TYPE3 -- 2021.06.18 품의서를 TCO포함으로 진행할 경우 계약금액은 도입금액 + TCO금액으로 한다. --, SUM(DT.EXEC_AMT) AS CONT_AMT ,(CASE WHEN HD.EXEC_TCO_FLAG = '1' THEN SUM(DT.EXEC_AMT) + SUM(DT.TCO_AMT) ELSE SUM(DT.EXEC_AMT) END) AS CONT_AMT FROM STOCCNDT DT JOIN STOCCNHD HD ON (HD.GATE_CD = DT.GATE_CD AND HD.BUYER_CD = DT.BUYER_CD AND HD.EXEC_NUM = DT.EXEC_NUM AND HD.DEL_FLAG = '0') WHERE DT.GATE_CD = #{ses.gateCd} AND DT.BUYER_CD = #{ses.companyCd} AND DT.EXEC_NUM || DT.EXEC_SQ IN
#{value}
AND DT.DEL_FLAG = '0' GROUP BY DT.GATE_CD, DT.BUYER_CD, DT.EXEC_NUM, DT.VENDOR_CD, DT.CONT_TYPE3, HD.EXEC_TCO_FLAG) CNDT ON (CNHD.GATE_CD = CNDT.GATE_CD AND CNHD.BUYER_CD = CNDT.BUYER_CD AND CNHD.EXEC_NUM = CNDT.EXEC_NUM) WHERE CNHD.GATE_CD = #{ses.gateCd} AND CNHD.BUYER_CD = #{ses.companyCd} AND CNHD.DEL_FLAG = '0' AND ROWNUM = 1

mapper.update:
		UPDATE STOCECHB
		   SET MOD_DATE = SYSDATE
			 , MOD_USER_ID = #{ses.userId}
			 , DEL_FLAG = '1'
		 WHERE GATE_CD  = #{ses.gateCd}
		   AND BUYER_CD = #{ses.companyCd}
  		   AND EXEC_NUM || EXEC_SQ IN 

			   #{value}

mapper.select:
		SELECT (CASE WHEN X.CONT_NUM_QTY > 0 THEN '1' ELSE '0' END) AS CONT_QTY
		  FROM (
			  	SELECT COUNT(*) AS CONT_NUM_QTY
				  FROM STOCECCT CT
			     WHERE CT.GATE_CD  = #{ses.gateCd}
			       AND CT.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd})
 				   AND CT.CONT_NUM = #{PRE_CONT_NUM}
				   AND CT.CONT_CNT > #{PRE_CONT_CNT}
				   AND CT.PROGRESS_CD < '4300'
				   AND CT.DEL_FLAG = '0'
		  ) X
		 WHERE 1 = 1

SELECT CONTRACT_TEXT_NUM
	 , CONTRACT_TEXT
  FROM STOCECRL
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{ses.companyCd}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND FORM_SQ  = 0
   AND DEL_FLAG = '0'
 ORDER BY FORM_SQ

SELECT CONTRACT_TEXT_NUM
	 , CONTRACT_TEXT
  FROM STOCECRL
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{ses.companyCd}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND DEL_FLAG = '0'
 ORDER BY FORM_SQ

SELECT X.* FROM ( SELECT ECCR.GATE_CD , ECRL.CONT_NUM , ECF2.FORM_TYPE ,GETCODENAME(ECF2.GATE_CD, 'M078', ECF2.FORM_TYPE, #{ses.langCd}) AS FORM_TYPE_NM , ECCR.FORM_NUM , ECCR.REL_FORM_NUM , ECCR.REL_FORM_SQ ,(ECCR.DEFAULT_FLAG, '0') AS DEFAULT_FLAG ,(ECCR.REQUIRE_FLAG, '0') AS REQUIRE_FLAG , ECF2.FORM_NM AS REL_FORM_NM , ECF2.FORM_TEXT_NUM , ECF2.FORM_TEXT ,(CASE WHEN ECRL.FORM_NUM IS NOT NULL THEN '1' ELSE '0' END) AS EXISTS_FLAG , ECF2.CONT_TYPE AS CONTRACT_FORM_TYPE ,(ECRL.REQUIRE_FLAG, '0') AS ECRL_REQUIRE_FLAG , ECF2.FORM_FILE_NM , ECRL.FORM_SQ FROM STOCECCF ECCF JOIN STOCECCR ECCR ON (ECCF.GATE_CD = ECCR.GATE_CD AND ECCF.FORM_NUM = ECCR.FORM_NUM AND ECCR.DEL_FLAG = '0') JOIN STOCECCF ECF2 ON (ECCR.GATE_CD = ECF2.GATE_CD AND ECCR.REL_FORM_NUM = ECF2.FORM_NUM AND ECF2.SIGN_STATUS = 'E'
AND (ECF2.BUYER_CD = #{ses.companyCd} OR ECF2.NH_COMM_FLAG = '1')
AND ECF2.BUYER_CD = #{ses.companyCd}
AND ECF2.DEL_FLAG = '0') LEFT JOIN STOCECRL ECRL ON (ECCR.GATE_CD = ECRL.GATE_CD AND ECCR.REL_FORM_NUM = ECRL.FORM_NUM
AND ECRL.CONT_NUM = #{PRE_CONT_NUM} AND ECRL.CONT_CNT = #{PRE_CONT_CNT}
AND ECRL.CONT_NUM = #{CONT_NUM} AND ECRL.CONT_CNT = #{CONT_CNT}
AND ECRL.FORM_SQ > 0 -- 부서식 AND ECRL.DEL_FLAG = '0') WHERE ECCF.GATE_CD = #{ses.gateCd} AND ECCF.FORM_NUM = #{FORM_NUM} AND ECCF.SIGN_STATUS = 'E' AND ECCF.DEL_FLAG = '0'
AND (ECCF.BUYER_CD = #{ses.companyCd} OR ECCF.NH_COMM_FLAG = '1')
AND ECCF.BUYER_CD = #{ses.companyCd}
AND UPPER(ECF2.FORM_NM) LIKE '%' UPPER(#{ADD_SEARCH}) '%'
AND ECCF.BUNDLE_FLAG = '1' --일괄계약 여부
AND UPPER(ECCF.FORM_NM) LIKE '%' UPPER(#{ADD_SEARCH}) '%'
) X WHERE 1 = 1 ORDER BY X.CONT_NUM , X.ECRL_REQUIRE_FLAG DESC , X.REQUIRE_FLAG DESC , X.DEFAULT_FLAG DESC , X.FORM_TYPE , X.REL_FORM_SQ , X.REL_FORM_NM

