			 , MOD_DATE
			 , MOD_USER_ID
			 , DEL_FLAG
			 , REQUIRE_FLAG
			 , FORM_SQ
			 , CONTRACT_TEXT_NUM
			 , FORM_CHECK_FLAG
			 , CONTRACT_TEXT
		) VALUES (
			   #{ses.gateCd}
			 , #{ses.companyCd}
			 , #{CONT_NUM}
			 , #{CONT_CNT}
			 , #{FORM_NUM}
			 , SYSDATE
			 , #{ses.userId}
			 , SYSDATE
			 , #{ses.userId}
			 , '0'
			 , #{REQUIRE_FLAG}
			 , #{FORM_SQ}
			 , #{CONTRACT_TEXT_NUM}
			 , #{FORM_CHECK_FLAG}
			 , #{CONTRACT_TEXT}
		)

        INSERT INTO STOCECRL (
			   GATE_CD
			 , BUYER_CD
			 , CONT_NUM
			 , CONT_CNT
			 , FORM_NUM
			 , REG_DATE
			 , REG_USER_ID
			 , MOD_DATE
			 , MOD_USER_ID
			 , DEL_FLAG
			 , REQUIRE_FLAG
			 , FORM_SQ
			 , CONTRACT_TEXT_NUM
			 , FORM_CHECK_FLAG
			 , CONTRACT_TEXT
		) VALUES (
			   #{ses.gateCd}
			 , #{ses.companyCd}
			 , #{CONT_NUM}
			 , #{CONT_CNT}
			 , #{REL_FORM_NUM}
			 , SYSDATE
			 , #{ses.userId}
			 , SYSDATE
			 , #{ses.userId}
			 , '0'
			 , #{REQUIRE_FLAG}
			 , (SELECT (MAX(FORM_SQ), 0) + 1
			 	  FROM STOCECRL
				 WHERE GATE_CD  = #{ses.gateCd}
				   AND BUYER_CD = #{ses.companyCd}
				   AND CONT_NUM = #{CONT_NUM}
				   AND CONT_CNT = #{CONT_CNT})
			 , #{CONTRACT_TEXT_NUM}
			 , #{FORM_CHECK_FLAG}
			 , #{CONTRACT_TEXT}
		)

mapper.update:
        UPDATE STOCECRL SET
			   MOD_DATE = SYSDATE
			 , MOD_USER_ID = #{ses.userId}
			 , CONTRACT_TEXT_NUM = #{CONTRACT_TEXT_NUM}
        	 , CONTRACT_TEXT = #{CONTRACT_TEXT}
		 WHERE GATE_CD  = #{ses.gateCd}
		   AND BUYER_CD = #{ses.companyCd}
		   AND CONT_NUM = #{CONT_NUM}
		   AND CONT_CNT = #{CONT_CNT}
		   AND FORM_SQ  = #{FORM_SQ}
		   AND DEL_FLAG = '0'

		DELETE FROM STOCECRL ECRL
		 WHERE ECRL.GATE_CD  = #{ses.gateCd}
		   AND ECRL.BUYER_CD = #{ses.companyCd}
		   AND ECRL.DEL_FLAG = '0'


		   AND EXISTS (SELECT 1 FROM STOCECCT
                        WHERE GATE_CD    = ECRL.GATE_CD
                          AND BUYER_CD   = ECRL.BUYER_CD
                          AND CONT_NUM   = ECRL.CONT_NUM
                          AND CONT_CNT   = ECRL.CONT_CNT
                          AND BUNDLE_NUM = #{BUNDLE_NUM})


		   AND ECRL.CONT_NUM = #{CONT_NUM}
		   AND ECRL.CONT_CNT = #{CONT_CNT}

mapper.select:
SELECT * FROM ( SELECT VNGL.VENDOR_NM , VNGL.CEO_USER_NM AS VENDOR_CEO_NM , VNGL.HQ_ADDR_1 ' ' VNGL.HQ_ADDR_2 AS VENDOR_ADDR , VNGL.IRS_NO AS VENDOR_IRS_NUM , VNGL.TEL_NO AS VENDOR_TEL_NUM , #{VENDOR_PIC_USER_NM} AS VENDOR_PIC_USER_NM , #{VENDOR_PIC_USER_EMAIL} AS VENDOR_PIC_EMAIL FROM STOCVNGL VNGL WHERE VNGL.GATE_CD = #{ses.gateCd} AND (VNGL.VENDOR_CD = #{VENDOR_CD}
OR VNGL.VENDOR_CD = (SELECT COMPANY_CD FROM STOCCVUR WHERE GATE_CD = VNGL.GATE_CD AND USER_ID = #{USER_ID})
) AND VNGL.DEL_FLAG = '0' ) X WHERE ROWNUM = 1

SELECT ECCT.BUYER_CD , ECCT.CONT_NUM , ECCT.CONT_CNT ,(ECCT.CREATE_TYPE, 'CN') AS CREATE_TYPE ,(SELECT MAX(CONT_CNT) FROM STOCECCT WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM) AS MAX_CONT_CNT , ECCT.CONT_NUM ' / ' ECCT.CONT_CNT AS CONT_NUM_AND_CNT ,(ECCT.CONT_DATE, 'YYYYMMDD') AS CONT_DATE ,(ECCT.CONT_START_DATE, 'YYYYMMDD') AS CONT_START_DATE ,(ECCT.CONT_END_DATE, 'YYYYMMDD') AS CONT_END_DATE , ECCT.CONT_DESC , ECCT.CONT_REQ_CD , ECCT.CUR , ECCT.CONT_AMT , ECCT.VAT_TYPE ,GETCODENAME(ECCT.GATE_CD, 'M100', ECCT.VAT_TYPE, #{ses.langCd}) AS VAT_TYPE_NM , ECCT.CONT_USER_ID ,GETUSERNAME(ECCT.GATE_CD, ECCT.CONT_USER_ID, #{ses.langCd}) AS CONT_USER_NM , ECCT.VENDOR_CD ,GETVENDORNAME(ECCT.GATE_CD, ECCT.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , ECCT.CERT_TYPE , ECCT.AMT_TYPE ,ECCT.VENDOR_PIC_USER_NM AS VENDOR_PIC_USER_NM ,ECCT.VENDOR_PIC_USER_EMAIL AS VENDOR_PIC_USER_EMAIL ,ECCT.VENDOR_PIC_USER_CELL_NUM AS VENDOR_PIC_USER_CELL_NUM , ECCT.DELAY_RMK , ECCT.DELAY_NUME_RATE , ECCT.DELAY_DENO_RATE , ECCT.STAMP_DUTY_FLAG , ECCT.STAMP_DUTY_AMT , ECCT.AUTO_RENEW_FLAG , ECCT.CONT_RMK , ECCT.ATT_FILE_NUM , ECCT.VENDOR_ATT_FILE_NUM , ECCT.PROGRESS_CD , ECCT.APP_DOC_NUM , ECCT.SIGN_STATUS , ECCT.APP_DOC_CNT ,(CASE WHEN ECCT.PROGRESS_CD < 4210 OR ECCT.PROGRESS_CD = '4220' THEN 'true' ELSE 'false' END) AS ATT_FILE_EDITABLE , ECRL.FORM_NUM , ECRL.FORM_NUM AS MAIN_FORM_NUM ,(SELECT CASE WHEN ECCT.BUNDLE_NUM IS NULL THEN MAX(ECPC.PDF_ATT_FILE_NUM) ELSE MAX(ECCM.PDF_ATT_FILE_NUM) END AS PDF_ATT_FILE_NUM FROM STOCECCM ECCM LEFT JOIN STOCECPC ECPC ON (ECCM.GATE_CD = ECPC.GATE_CD AND ECCM.BUYER_CD = ECPC.BUYER_CD AND ECCM.CONT_NUM = ECPC.CONT_NUM AND ECCM.CONT_CNT = ECPC.CONT_CNT AND ECCM.PR_BUYER_CD = ECPC.PR_BUYER_CD AND ECCM.PR_DEPT_CD = ECPC.PR_DEPT_CD AND ECCM.VENDOR_CD = ECPC.VENDOR_CD AND ECPC.PAY_CNT = '0' AND ECPC.DEL_FLAG = '0') WHERE ECCM.GATE_CD = ECCT.GATE_CD AND ECCM.BUYER_CD = ECCT.BUYER_CD AND ECCM.CONT_NUM = ECCT.CONT_NUM AND ECCM.CONT_CNT = ECCT.CONT_CNT AND ECCM.DEL_FLAG = '0') AS PDF_ATT_FILE_NUM
, ECRL.CONTRACT_TEXT_NUM
,(SELECT CONTENTS_TEXT_NUM FROM STOCSCTM WHERE GATE_CD = ECCT.GATE_CD AND APP_DOC_NUM = ECCT.APP_DOC_NUM AND APP_DOC_CNT = #{APP_DOC_CNT} AND BUYER_CD = (#{BUYER_CD}, #{ses.companyCd})) AS CONTRACT_TEXT_NUM
, ECRL.CONTRACT_TEXT , ECCF.FORM_TEXT_NUM , ECCF.FORM_TEXT , ECCT.DEPT_CD ,(SELECT MIN(ECRJ.REJECT_RMK) KEEP(DENSE_RANK FIRST ORDER BY ECRJ.REJECT_SQ DESC) AS REJECT_RMK FROM STOCECRJ ECRJ WHERE ECRJ.GATE_CD = ECCT.GATE_CD AND ECRJ.BUYER_CD = ECCT.BUYER_CD AND ECRJ.CONT_NUM = ECCT.CONT_NUM AND ECRJ.CONT_CNT = ECCT.CONT_CNT) AS VENDOR_REJECT_RMK ,(SELECT A.REJECT_RMK FROM STOCECRJ A WHERE A.GATE_CD = ECCT.GATE_CD AND A.CONT_NUM = ECCT.CONT_NUM AND A.CONT_CNT = ECCT.CONT_CNT AND A.REJECT_SQ = (SELECT MAX(B.REJECT_SQ) FROM STOCECRJ B WHERE B.GATE_CD = A.GATE_CD AND B.CONT_NUM = A.CONT_NUM AND B.CONT_CNT = A.CONT_CNT)) AS CONT_REJECT_RMK -- 협력사 전자서명 반려사유 ,(SELECT CASE WHEN ECCT.BUNDLE_NUM IS NULL THEN ( SELECT LISTAGG('' || ATCH.HASH_NUM, ',') WITHIN GROUP(ORDER BY ATCH.HASH_NUM) FROM STOCECCM ECCM JOIN STOCECPC ECPC ON (ECCM.GATE_CD = ECPC.GATE_CD AND ECCM.BUYER_CD = ECPC.BUYER_CD AND ECCM.CONT_NUM = ECPC.CONT_NUM AND ECCM.CONT_CNT = ECPC.CONT_CNT AND ECCM.PR_BUYER_CD = ECPC.PR_BUYER_CD AND ECCM.PR_DEPT_CD = ECPC.PR_DEPT_CD AND ECCM.VENDOR_CD = ECPC.VENDOR_CD AND ECPC.PAY_CNT = '0' AND ECPC.DEL_FLAG = '0') JOIN STOCATCH ATCH ON (ECPC.GATE_CD = ATCH.GATE_CD AND ECPC.PDF_ATT_FILE_NUM = ATCH.UUID) WHERE ECCM.GATE_CD = ECCT.GATE_CD AND ECCM.BUYER_CD = ECCT.BUYER_CD AND ECCM.CONT_NUM = ECCT.CONT_NUM AND ECCM.CONT_CNT = ECCT.CONT_CNT AND ECCM.DEL_FLAG = '0') ELSE (SELECT LISTAGG('' || ATCH.HASH_NUM, ',') WITHIN GROUP(ORDER BY ATCH.HASH_NUM) FROM STOCECCM ECCM JOIN STOCATCH ATCH ON (ECCM.GATE_CD = ATCH.GATE_CD AND ECCM.PDF_ATT_FILE_NUM = ATCH.UUID) WHERE ECCM.GATE_CD = ECCT.GATE_CD AND ECCM.BUYER_CD = ECCT.BUYER_CD AND ECCM.CONT_NUM = ECCT.CONT_NUM AND ECCM.CONT_CNT = ECCT.CONT_CNT AND ECCM.DEL_FLAG = '0') END FROM DUAL) AS HASH_NUM ,(SELECT CASE WHEN COUNT(*) > 0 THEN 'BID' ELSE NULL END FROM STOCECMT ECMT JOIN STOCCNDT CNDT ON (ECMT.GATE_CD = CNDT.GATE_CD AND ECMT.BUYER_CD = CNDT.BUYER_CD AND ECMT.EXEC_NUM = CNDT.EXEC_NUM AND ECMT.EXEC_SQ = CNDT.EXEC_SQ AND CNDT.RFX_TYPE = 'BID') WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0') AS CONT_BID_GBN ,(ECCT.VENDOR_SEND_FLAG, '0') AS VENDOR_SEND_FLAG -- 계약서 협력사 공유여부(2021.03.08 추가) ,SUBSTR((SELECT MAX(PRHD.IF_TYPE) FROM STOCECMT ECMT JOIN STOCPRDT PRDT ON (PRDT.GATE_CD = ECMT.GATE_CD AND PRDT.BUYER_CD = ECMT.PB_BUYER_CD AND PRDT.PR_NUM = ECMT.PR_NUM AND PRDT.PR_SQ = ECMT.PR_SQ AND PRDT.DEL_FLAG = '0') JOIN STOCPRHD PRHD ON (PRHD.GATE_CD = PRDT.GATE_CD AND PRHD.BUYER_CD = PRDT.BUYER_CD AND PRHD.PR_NUM = PRDT.PR_NUM AND PRHD.IF_TYPE IS NOT NULL AND PRHD.DEL_FLAG = '0') WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0'), 1, 2) AS IF_TYPE ,(SELECT MAX(PRDT.PRE_CONT_NUM) FROM STOCECMT ECMT JOIN STOCPRDT PRDT ON (PRDT.GATE_CD = ECMT.GATE_CD AND PRDT.BUYER_CD = ECMT.PB_BUYER_CD AND PRDT.PR_NUM = ECMT.PR_NUM AND PRDT.PR_SQ = ECMT.PR_SQ AND PRDT.DEL_FLAG = '0') JOIN STOCPRHD PRHD ON (PRDT.GATE_CD = PRHD.GATE_CD AND PRDT.BUYER_CD = PRHD.BUYER_CD AND PRDT.PR_NUM = PRHD.PR_NUM AND PRHD.IF_TYPE IN ('ITA', 'ITB') -- IT포탈 I/F 데이터 AND PRHD.PR_TYPE IN ('20', '30') -- 변경(20), 연장(30) 계약 AND PRHD.DEL_FLAG = '0') WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0') AS PRE_CONT_NUM FROM STOCECCT ECCT LEFT JOIN STOCECRL ECRL ON (ECCT.GATE_CD = ECRL.GATE_CD AND ECCT.BUYER_CD = ECRL.BUYER_CD AND ECCT.CONT_NUM = ECRL.CONT_NUM AND ECCT.CONT_CNT = ECRL.CONT_CNT
AND ECRL.FORM_NUM = #{formNum}
AND ECRL.FORM_SQ = '0'
