SELECT A.* FROM ( SELECT GETCOMCODE(ECPC.GATE_CD, 'M404', ECPC.GUAR_TYPE, 0, #{ses.langCd}) AS GUAR_TYPE , (SELECT CONT_DESC FROM STOCECCT WHERE GATE_CD = ECPC.GATE_CD AND BUYER_CD = ECPC.BUYER_CD AND CONT_NUM = ECPC.CONT_NUM AND CONT_CNT = ECPC.CONT_CNT AND VENDOR_CD = ECPC.VENDOR_CD AND DEL_FLAG = '0') AS CONT_DESC , ECPC.VENDOR_CD , GETVENDORNAME(ECPC.GATE_CD, ECPC.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , CVUR.USER_ID , CVUR.USER_NM AS USER_NM , (SYSDATE, 'YYYY-MM-DD') AS SYS_DATE FROM STOCECPC ECPC JOIN STOCCVUR CVUR ON (CVUR.GATE_CD = ECPC.GATE_CD AND CVUR.COMPANY_CD = ECPC.VENDOR_CD AND CVUR.BLOCK_FLAG = '0' AND CVUR.MAIL_FLAG = '1' AND CVUR.EMAIL IS NOT NULL AND CVUR.DEL_FLAG = '0') WHERE ECPC.GATE_CD = #{ses.gateCd} AND ECPC.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd}) AND ECPC.CONT_NUM = #{CONT_NUM} AND ECPC.CONT_CNT = #{CONT_CNT} AND ECPC.PR_BUYER_CD = #{PR_BUYER_CD} AND ECPC.PR_DEPT_CD = #{PR_DEPT_CD} AND ECPC.VENDOR_CD = #{VENDOR_CD}
AND ECPC.PAY_CNT = #{PAY_CNT}
AND ECPC.GUAR_TYPE = #{GUAR_TYPE} AND ECPC.GUAR_PERCENT > 0 AND ECPC.DEL_FLAG = '0' ORDER BY CVUR.MNG_YN DESC ) A WHERE ROWNUM <= 2

		SELECT (CASE WHEN X.CONT_NUM_QTY > 0 THEN '1' ELSE '0' END) AS CONT_QTY
		  FROM (
			  	SELECT COUNT(*) AS CONT_NUM_QTY
				  FROM STOCECCT CT
			     WHERE CT.GATE_CD  = #{ses.gateCd}
			       AND CT.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd})
 				   AND CT.CONT_NUM = #{CONT_NUM}
				   AND CT.CONT_CNT = #{NEW_CONT_CNT}
		  ) X
		 WHERE 1 = 1

SELECT A.* ,(CASE WHEN A.PROGRESS_CD < 4210 OR A.PROGRESS_CD = '4220' THEN 'true' ELSE 'false' END) AS ATT_FILE_EDITABLE FROM ( SELECT ECCT.BUYER_CD , ECCT.CONT_NUM , ECCT.CONT_CNT , ECCT.BUNDLE_NUM , (ECCT.CONT_DATE, 'YYYYMMDD') AS CONT_DATE , (ECCT.CONT_START_DATE, 'YYYYMMDD') AS CONT_START_DATE , (ECCT.CONT_END_DATE, 'YYYYMMDD') AS CONT_END_DATE , ECCT.CONT_DESC , ECCT.CONT_REQ_CD , ECCT.CUR , ECCT.CONT_AMT , ECCT.VAT_TYPE , ECCT.CONT_USER_ID , GETUSERNAME(ECCT.GATE_CD, ECCT.CONT_USER_ID, #{ses.langCd}) AS CONT_USER_NM , ECRL.CONTRACT_TEXT_NUM , ECRL.CONTRACT_TEXT , ECRL.FORM_NUM AS MAIN_FORM_NUM , ECCT.CERT_TYPE , ECCT.AUTO_RENEW_FLAG , ECCT.CONT_RMK ,(SELECT MAX(PROGRESS_CD) FROM STOCECCT WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND BUNDLE_NUM = ECCT.BUNDLE_NUM
AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT
AND DEL_FLAG = '0') AS PROGRESS_CD , ECCT.SIGN_STATUS , ECCT.ATT_FILE_NUM , ECCT.VENDOR_ATT_FILE_NUM ,(SELECT (MAX(SIGN_DATE), 'YYYYMMDD') FROM STOCECSV WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND USER_TYPE = 'B' AND ROWNUM = 1) AS BUYER_SIGN_DATE ,(SELECT (MAX(SIGN_DATE), 'YYYYMMDD') FROM STOCECSV WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND VENDOR_CD = ECCT.VENDOR_CD AND USER_TYPE = 'S' AND ROWNUM = 1) AS VENDOR_SIGN_DATE , ECRL.FORM_NUM , ECCT.APP_DOC_NUM , ECCT.APP_DOC_CNT , ECCF.CONT_TYPE ,(SELECT ATCH.HASH_NUM FROM STOCECCM ECCM JOIN STOCATCH ATCH ON (ECCM.GATE_CD = ATCH.GATE_CD AND ECCM.PDF_ATT_FILE_NUM = ATCH.UUID) WHERE ECCM.GATE_CD = ECCT.GATE_CD AND ECCM.BUYER_CD = ECCT.BUYER_CD AND ECCM.CONT_NUM = ECCT.CONT_NUM AND ECCM.CONT_CNT = ECCT.CONT_CNT AND ECCM.DEL_FLAG = '0' AND ROWNUM = 1) AS HASH_NUM , (SELECT CASE WHEN COUNT(*) > 0 THEN 'BID' ELSE NULL END FROM STOCECMT ECMT JOIN STOCCNDT CNDT ON (ECMT.GATE_CD = CNDT.GATE_CD AND ECMT.BUYER_CD = CNDT.BUYER_CD AND ECMT.EXEC_NUM = CNDT.EXEC_NUM AND ECMT.EXEC_SQ = CNDT.EXEC_SQ AND CNDT.RFX_TYPE = 'BID') WHERE ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0') AS CONT_BID_GBN , (SELECT PR_BUYER_CD FROM STOCECCM WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND DEL_FLAG = '0' AND ROWNUM = 1) AS PR_BUYER_CD , (SELECT PR_DEPT_CD FROM STOCECCM WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND DEL_FLAG = '0' AND ROWNUM = 1) AS PR_DEPT_CD , GETCUSTNAME(#{ses.gateCd}, (SELECT PR_BUYER_CD FROM STOCECCM WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND DEL_FLAG = '0' AND ROWNUM = 1)) ' ' GETDEPTNAME(#{ses.gateCd}, (SELECT PR_BUYER_CD FROM STOCECCM WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND DEL_FLAG = '0' AND ROWNUM = 1), (SELECT PR_DEPT_CD FROM STOCECCM WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND DEL_FLAG = '0' AND ROWNUM = 1), #{ses.langCd}) AS PR_BUYER_DEPT_NM , (SELECT PDF_ATT_FILE_NUM FROM STOCECCM WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ECCT.CONT_CNT AND DEL_FLAG = '0' AND ROWNUM = 1) AS PDF_ATT_FILE_NUM FROM STOCECCT ECCT LEFT JOIN STOCECRL ECRL ON (ECCT.GATE_CD = ECRL.GATE_CD AND ECCT.BUYER_CD = ECRL.BUYER_CD AND ECCT.CONT_NUM = ECRL.CONT_NUM AND ECCT.CONT_CNT = ECRL.CONT_CNT AND ECRL.FORM_SQ = '0' AND ECRL.DEL_FLAG = '0') LEFT JOIN STOCECCF ECCF ON (ECRL.GATE_CD = ECCF.GATE_CD /** 2020.08.11 제외 AND ECRL.BUYER_CD = ECCF.BUYER_CD*/ AND ECRL.FORM_NUM = ECCF.FORM_NUM) LEFT JOIN STOCVNGL VNGL ON (VNGL.GATE_CD = ECCT.GATE_CD AND VNGL.VENDOR_CD = ECCT.VENDOR_CD) WHERE ECCT.GATE_CD = #{ses.gateCd} AND ECCT.DEL_FLAG = '0'
AND (ECCF.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd}) OR ECCF.NH_COMM_FLAG = '1')
AND ECCF.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd})
AND ECCT.CONT_NUM = #{CONT_NUM} AND ECCT.CONT_CNT = #{CONT_CNT}
AND ECCT.APP_DOC_NUM = #{APP_DOC_NUM} AND ECCT.APP_DOC_CNT = #{APP_DOC_CNT}
AND ECCT.BUNDLE_NUM = #{BUNDLE_NUM}
AND ROWNUM = 1 ) A WHERE 1 = 1

SELECT MAX(ECCT.PROGRESS_CD) AS PROGRESS_CD
  FROM STOCECCT ECCT
 WHERE ECCT.GATE_CD  = #{ses.gateCd}
   AND ECCT.BUYER_CD = #{BUYER_CD}
   AND ECCT.DEL_FLAG = '0'


   AND ECCT.BUNDLE_NUM = #{BUNDLE_NUM}


   AND ECCT.CONT_NUM = #{CONT_NUM}
   AND ECCT.CONT_CNT = #{CONT_CNT}

SELECT VNGL.VENDOR_CD , VNGL.VENDOR_NM FROM STOCVNGL VNGL WHERE VNGL.GATE_CD = #{ses.gateCd} AND VNGL.VENDOR_CD IN
#{value}
AND VNGL.DEL_FLAG = '0'

SELECT CNDT.PR_BUYER_CD , CNDT.PR_DEPT_CD , GETBUYERDEPTNAME(CNDT.GATE_CD, CNDT.PR_BUYER_CD, CNDT.PR_DEPT_CD, #{ses.langCd}) AS PR_BUYER_DEPT_NM , CNDT.VENDOR_CD , CNDT.PURCHASE_TYPE , CNDT.ITEM_CD , CNDT.ITEM_DESC , CNDT.ITEM_SPEC , CNDT.MAKER_CD , GETMKBRNAME(CNDT.GATE_CD, CNDT.BUYER_CD, 'MK', CNDT.MAKER_CD) AS MAKER_NM , CNDT.MAKER_PART_NO , CNDT.ORIGIN_CD , GETCOMCODE(CNDT.GATE_CD, 'M004', CNDT.ORIGIN_CD, 0, #{ses.langCd}) AS ORIGIN_NM , CNDT.EXEC_QT AS ITEM_QT , CNDT.UNIT_CD -- 2021.06.18 변경 (TCO인 경우 계약금액 = 도입금액 + TCO금액) --, CNDT.EXEC_AMT / EXEC_QT AS ITEM_PRC --, CNDT.EXEC_AMT AS ITEM_AMT ,(CASE WHEN CNHD.EXEC_TCO_FLAG = '1' THEN (CNDT.EXEC_AMT, 0) + (CNDT.TCO_AMT, 0) ELSE (CNDT.EXEC_AMT, 0) END) / (CNDT.EXEC_QT, 1) AS ITEM_PRC ,(CASE WHEN CNHD.EXEC_TCO_FLAG = '1' THEN (CNDT.EXEC_AMT, 0) + (CNDT.TCO_AMT, 0) ELSE (CNDT.EXEC_AMT, 0) END) AS ITEM_AMT -- 구매유형이 용역 인 경우 필수 , CNDT.SW_BUS_PRICE AS SW_BIZ_AMT -- SW 사업대가 , CNDT.MNT_SANGJU_YN -- 상주여부 -- 구매유형이 물품/공사 인 경우 필수 , CNDT.CONSUMER_AMT -- 소비자금액 , CNDT.FC_MNT_TERM -- 무상유지보수기간 , CNDT.CH_RATE -- 유상요율 -- 구매유형이 유지보수 인 경우 필수 , CNDT.DOIB_AMT AS DOIB_AMOUNT -- 도입금액 , CNDT.MNT_RATE -- 유지보수요율 , (CNDT.MNT_SDAY, 'YYYYMMDD') AS MNT_SDAY -- 유지보수시작일 , (CNDT.MNT_EDAY, 'YYYYMMDD') AS MNT_EDAY -- 유지보수종료일 , CNDT.MNT_GUR_MONTH -- 개월수 , CNDT.RT_INSP_PERIOD -- 정기점검주기 , CNDT.FALT_RC_TG_TIME -- 장애복구묙표시간 , (CNDT.DUE_DATE, 'YYYYMMDD') AS DUE_DATE -- 납기요청일 ,(SELECT CONT_WT_NUM FROM STOCECHB WHERE GATE_CD = CNDT.GATE_CD AND BUYER_CD = CNDT.BUYER_CD AND EXEC_NUM = CNDT.EXEC_NUM AND EXEC_SQ = CNDT.EXEC_SQ) AS CONT_WT_NUM , CNDT.EXEC_NUM , CNDT.EXEC_SQ , CNDT.PB_BUYER_CD , CNDT.PR_NUM , CNDT.PR_SQ ,(SELECT IF_TYPE FROM STOCPRHD WHERE GATE_CD = PRDT.GATE_CD AND BUYER_CD = PRDT.BUYER_CD AND PR_NUM = PRDT.PR_NUM) AS IF_TYPE ,(SELECT IF_TYPE FROM STOCPRHD WHERE GATE_CD = PRDT.GATE_CD AND BUYER_CD = PRDT.BUYER_CD AND PR_NUM = PRDT.PR_NUM) AS IF_TYPE_CD , PRDT.PRE_BUYER_CD , PRDT.PRE_CONT_NUM , PRDT.PRE_CONT_CNT , PRDT.CM_REQ_ID , PRDT.MULPUM_ID FROM STOCCNDT CNDT JOIN STOCCNHD CNHD ON (CNHD.GATE_CD = CNDT.GATE_CD AND CNHD.BUYER_CD = CNDT.BUYER_CD AND CNHD.EXEC_NUM = CNDT.EXEC_NUM AND CNHD.DEL_FLAG = '0') LEFT JOIN STOCPRDT PRDT ON (PRDT.GATE_CD = CNDT.GATE_CD AND PRDT.BUYER_CD = CNDT.PB_BUYER_CD AND PRDT.PR_NUM = CNDT.PR_NUM AND PRDT.PR_SQ = CNDT.PR_SQ) WHERE CNDT.GATE_CD = #{ses.gateCd} AND CNDT.BUYER_CD = #{ses.companyCd} AND CNDT.EXEC_NUM || CNDT.EXEC_SQ IN
#{value}
AND CNDT.DEL_FLAG = '0' ORDER BY CNDT.EXEC_SQ

SELECT PRDT.PR_BUYER_CD , PRDT.PR_DEPT_CD ,GETBUYERDEPTNAME(PRDT.GATE_CD, PRDT.PR_BUYER_CD, PRDT.PR_DEPT_CD, #{ses.langCd}) AS PR_BUYER_DEPT_NM ,(SELECT MAX(VENDOR_CD) FROM STOCECCT WHERE GATE_CD = PRDT.GATE_CD AND BUYER_CD = #{PRE_BUYER_CD} AND CONT_NUM = #{PRE_CONT_NUM} AND CONT_CNT = #{PRE_CONT_CNT}) AS VENDOR_CD -- 계약협력사는 이전계약번호의 협력사로 자동 세팅 , PRDT.PURCHASE_TYPE , PRDT.ITEM_CD , PRDT.ITEM_DESC , PRDT.ITEM_SPEC , PRDT.MAKER_CD ,GETMKBRNAME(PRDT.GATE_CD, PRDT.BUYER_CD, 'MK', PRDT.MAKER_CD) AS MAKER_NM , PRDT.MAKER_PART_NO , PRDT.ORIGIN_CD ,GETCOMCODE(PRDT.GATE_CD, 'M004', PRDT.ORIGIN_CD, 0, #{ses.langCd}) AS ORIGIN_NM , PRDT.PR_QT AS ITEM_QT , PRDT.UNIT_CD ,(PRDT.PR_AMT, 0) / (PRDT.PR_QT, 1) AS ITEM_PRC , PRDT.PR_AMT AS ITEM_AMT -- 구매유형이 용역 인 경우 필수 , NULL AS SW_BIZ_AMT -- SW 사업대가 , PRDT.MNT_SANGJU_YN -- 상주여부 -- 구매유형이 물품/공사 인 경우 필수 , PRDT.CONSUMER_AMT -- 소비자금액 , PRDT.FC_MNT_TERM -- 무상유지보수기간 , PRDT.CH_RATE -- 유상요율 -- 구매유형이 유지보수 인 경우 필수 , PRDT.DOIB_AMT AS DOIB_AMOUNT -- 도입금액 , PRDT.MNT_RATE -- 유지보수요율 ,(PRDT.MNT_SDAY, 'YYYYMMDD') AS MNT_SDAY -- 유지보수시작일 ,(PRDT.MNT_EDAY, 'YYYYMMDD') AS MNT_EDAY -- 유지보수종료일 , PRDT.MNT_GUR_MONTH -- 개월수 , PRDT.RT_INSP_PERIOD -- 정기점검주기 , PRDT.FALT_RC_TG_TIME -- 장애복구묙표시간 ,(PRDT.DUE_DATE, 'YYYYMMDD') AS DUE_DATE -- 납기요청일 , PRDT.BUYER_CD AS PB_BUYER_CD , PRDT.PR_NUM , PRDT.PR_SQ , PRHD.IF_TYPE , PRHD.IF_TYPE AS IF_TYPE_CD , PRDT.PRE_BUYER_CD , PRDT.PRE_CONT_NUM , PRDT.PRE_CONT_CNT , PRDT.CM_REQ_ID , PRDT.MULPUM_ID FROM STOCPRDT PRDT JOIN STOCPRHD PRHD ON (PRHD.GATE_CD = PRDT.GATE_CD AND PRHD.BUYER_CD = PRDT.BUYER_CD AND PRHD.PR_NUM = PRDT.PR_NUM) WHERE PRDT.GATE_CD = #{ses.gateCd} AND PRDT.BUYER_CD || PRDT.PR_NUM || PRDT.PR_SQ IN
#{value}
AND PRDT.DEL_FLAG = '0' ORDER BY PRDT.PR_SQ

SELECT (MAX(CONT_CNT) + 1, 1) AS CONT_CNT
  FROM STOCECCT
 WHERE GATE_CD  = #{ses.gateCd}
   AND CONT_NUM = #{CONT_NUM}

SELECT ECCT.BUYER_CD , ECCT.CONT_NUM , ECCT.CONT_CNT , ECCT.VENDOR_CD , GETBUYERDEPTNAME(ECCM.GATE_CD, ECCM.VENDOR_CD, ECCM.VENDOR_DEPT_CD, #{ses.langCd}) AS VENDOR_NM , ECCT.PROGRESS_CD , ECCT.VENDOR_PIC_USER_NM AS VENDOR_PIC_USER_NM , ECCT.VENDOR_PIC_USER_EMAIL AS VENDOR_PIC_USER_EMAIL , ECCT.VENDOR_PIC_USER_CELL_NUM AS VENDOR_PIC_USER_CELL_NUM , ECCT.VENDOR_ATT_FILE_NUM ,(SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = #{ses.gateCd} AND UUID = ECCT.VENDOR_ATT_FILE_NUM AND DEL_FLAG = '0') AS VENDOR_ATT_FILE_CNT , ECCT.APP_DOC_NUM , ECCT.APP_DOC_CNT , ECRL.CONTRACT_TEXT_NUM , ECCT.AUTO_RENEW_FLAG , ECCM.PR_DEPT_CD , ECCM.VENDOR_DEPT_CD , ECCM.PDF_ATT_FILE_NUM ,(SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = #{ses.gateCd} AND UUID = ECCM.PDF_ATT_FILE_NUM AND DEL_FLAG = '0') AS PDF_ATT_FILE_CNT FROM STOCECCT ECCT JOIN STOCECRL ECRL ON (ECCT.GATE_CD = ECRL.GATE_CD AND ECCT.BUYER_CD = ECRL.BUYER_CD AND ECCT.CONT_NUM = ECRL.CONT_NUM AND ECCT.CONT_CNT = ECRL.CONT_CNT AND ECRL.FORM_SQ = '0' AND ECRL.DEL_FLAG = '0') JOIN STOCECCF ECCF ON (ECRL.GATE_CD = ECCF.GATE_CD AND ECRL.FORM_NUM = ECCF.FORM_NUM AND ECCF.DEL_FLAG = '0') JOIN STOCECCM ECCM ON (ECCT.GATE_CD = ECCM.GATE_CD AND ECCT.BUYER_CD = ECCM.BUYER_CD AND ECCT.CONT_NUM = ECCM.CONT_NUM AND ECCT.CONT_CNT = ECCM.CONT_CNT AND ECCT.VENDOR_CD = ECCM.VENDOR_CD AND ECCM.DEL_FLAG = '0') WHERE ECCT.GATE_CD = #{ses.gateCd} AND ECCT.BUNDLE_NUM = #{BUNDLE_NUM} AND ECCT.DEL_FLAG = '0'
AND (ECCF.BUYER_CD = #{ses.companyCd} OR ECCF.NH_COMM_FLAG = '1')
AND ECCF.BUYER_CD = #{ses.companyCd}
AND ECCM.VENDOR_CD = #{VENDOR_CD}
AND ECCT.CONT_NUM = #{CONT_NUM} AND ECCT.CONT_CNT = #{CONT_CNT}
AND ECCM.PR_BUYER_CD = #{PR_BUYER_CD}
AND ECCM.PR_DEPT_CD = #{PR_DEPT_CD}
AND ECCM.PR_BUYER_CD = #{PR_BUYER_CD}
AND ECCM.PR_DEPT_CD = #{PR_DEPT_CD}
AND ECCM.VENDOR_CD = #{VENDOR_CD}

SELECT BUYER_CD
     , PO_NUM
  FROM STOCPODT
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
 GROUP BY BUYER_CD, PO_NUM

     SELECT (ECCT.EFORM_INPUT_VALUE_CLOB, ' ') AS EFORM_INPUT_VALUE_CLOB
	   FROM STOCECCT ECCT
	  WHERE ECCT.GATE_CD  = #{ses.gateCd}
	    AND ECCT.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd})

	    AND ECCT.BUNDLE_NUM = #{BUNDLE_NUM}

	    AND ECCT.CONT_NUM = #{CONT_NUM}
	    AND ECCT.CONT_CNT = #{CONT_CNT}
	    AND ECCT.DEL_FLAG = '0'

SELECT ((CASE WHEN #{PROGRESS_CD} = '4200' AND #{PRE_CONT_NUM} IS NOT NULL THEN (ECCT.EFORM_INPUT_VALUE_CLOB, (SELECT EFORM_INPUT_VALUE_CLOB FROM STOCECCT WHERE GATE_CD = ECCT.GATE_CD AND BUYER_CD = ECCT.BUYER_CD AND CONT_NUM = ECCT.CONT_NUM AND CONT_CNT = ${CONT_CNT} - 1)) ELSE ECCT.EFORM_INPUT_VALUE_CLOB END), ' ') AS EFORM_INPUT_VALUE_CLOB FROM STOCECCT ECCT WHERE ECCT.GATE_CD = #{ses.gateCd} AND ECCT.BUYER_CD = (#{BUYER_CD}, #{ses.companyCd})
AND ECCT.BUNDLE_NUM = #{BUNDLE_NUM}
AND ECCT.CONT_NUM = #{CONT_NUM} AND ECCT.CONT_CNT = #{CONT_CNT} AND ECCT.DEL_FLAG = '0'

SELECT (CASE WHEN COUNT(*) > 0 THEN 'Y' ELSE 'N' END) AS GUAR_FLAG
  FROM STOCECPC
 WHERE GATE_CD  = #{ses.gateCd}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND GUAR_CANCEL_STATUS = 'J'

SELECT COUNT(*) AS CNT
  FROM STOCECPC
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{ses.companyCd}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND SIGN_ID  IS NULL
   AND PAY_CNT  = '0'

SELECT COUNT(*)
  FROM STOCECSV
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{ses.companyCd}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND SIGN_ID  = #{ses.userId}

SELECT COUNT(*) AS CNT
  FROM STOCECPC
 WHERE GATE_CD  = #{ses.gateCd}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND SIGN_ID  IS NULL
   AND SIGN_FLAG = '1'
   AND PAY_CNT  = '0'

	SELECT HASH_NUM
      FROM STOCATCH
	 WHERE GATE_CD = #{ses.gateCd}
	   AND UUID	= (
                SELECT PDF_ATT_FILE_NUM
                  FROM STOCECCM
                 WHERE GATE_CD   = #{ses.gateCd}
                   AND BUYER_CD  =  (#{BUYER_CD}, #{ses.companyCd})
                   AND CONT_NUM  = #{CONT_NUM}
                   AND CONT_CNT  = #{CONT_CNT}
                   AND PR_BUYER_CD = #{PR_BUYER_CD}
                   AND PR_DEPT_CD  = #{PR_DEPT_CD}
                   AND VENDOR_CD = #{VENDOR_CD}       
       )
      AND ROWNUM = 1
